compliant:
// Proper mutex initialization and destruction
pthread_mutex_t mutex;
int shared_data = 0;

void initialize_mutex() {
    pthread_mutex_init(&mutex, NULL);  // Compliant: proper initialization
}

void* thread_function(void* arg) {
    pthread_mutex_lock(&mutex);
    shared_data++;
    pthread_mutex_unlock(&mutex);
    return NULL;
}

void cleanup_mutex() {
    pthread_mutex_destroy(&mutex);  // Compliant: proper cleanup
}

// Using static initialization
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;  // Compliant
int shared_data = 0;

void* thread_function(void* arg) {
    pthread_mutex_lock(&mutex);
    shared_data++;
    pthread_mutex_unlock(&mutex);
    return NULL;
}
